/**
 * BTAvatar v2 styles. Plain CSS (not modules). Mirrors @btech/ui-vue
 * exactly — when one updates, both update. Component-specific brand
 * palette is HARDCODED per the figma-visual-rule + component-specific-
 * colors policy.
 */

.btech-avatar {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  border-radius: var(--radius-rd, 9999px);
  overflow: hidden;
  position: relative;
  flex-shrink: 0;
  font-family: 'Geist', system-ui, -apple-system, sans-serif;
  font-weight: 500;
  letter-spacing: var(--letterSpacing-normal, 0);
  text-align: center;
  user-select: none;
}

/* ── Sizes (Figma 497:979 ramp) ─────────────────────────────────────── */
.btech-avatar--xs  { width: 24px; height: 24px; font-size: var(--fontSize-2xs, 10px); line-height: var(--lineHeight-xs, 16px); }
.btech-avatar--sm  { width: 32px; height: 32px; font-size: var(--fontSize-sm, 14px); line-height: var(--lineHeight-xs, 16px); }
.btech-avatar--md  { width: 40px; height: 40px; font-size: var(--fontSize-md, 16px); line-height: var(--lineHeight-sm, 20px); }
.btech-avatar--lg  { width: 48px; height: 48px; font-size: var(--fontSize-xl, 20px); line-height: var(--lineHeight-md, 24px); }
.btech-avatar--xl  { width: 64px; height: 64px; font-size: var(--fontSize-3xl, 28px); line-height: var(--lineHeight-xl, 32px); }
.btech-avatar--2xl { width: 96px; height: 96px; font-size: var(--fontSize-5xl, 40px); line-height: var(--lineHeight-4xl, 48px); }

/* ── Component-specific palette — HARDCODED per figma-visual-rule ───── */
.btech-avatar--initials              { color: var(--text-inverse, #ffffff); }
.btech-avatar--color-green   { background: #89ae68; }
.btech-avatar--color-blue    { background: #93c6ef; }
.btech-avatar--color-orange  { background: #fc7b1f; }
.btech-avatar--color-purple  { background: #8873bd; }
.btech-avatar--color-teal    { background: #2fa0a1; }
.btech-avatar--color-pink    { background: #f37a98; }

/* ── Image variant ──────────────────────────────────────────────────── */
.btech-avatar--image .btech-avatar__img {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  object-fit: cover;
  border-radius: inherit;
}

/* ── Empty + Error variants (Figma 497:979) — bg/subtler + icon ─────── */
.btech-avatar--empty,
.btech-avatar--error {
  background: var(--bg-subtler, #dbdde1);
}
.btech-avatar__icon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  color: var(--text-secondary, #64748b);
}
/* Scale SVG icon ~56% of avatar diameter */
.btech-avatar--xs  .btech-avatar__icon svg { width: 14px; height: 14px; }
.btech-avatar--sm  .btech-avatar__icon svg { width: 18px; height: 18px; }
.btech-avatar--md  .btech-avatar__icon svg { width: 22px; height: 22px; }
.btech-avatar--lg  .btech-avatar__icon svg { width: 26px; height: 26px; }
.btech-avatar--xl  .btech-avatar__icon svg { width: 36px; height: 36px; }
.btech-avatar--2xl .btech-avatar__icon svg { width: 54px; height: 54px; }

/* ── Loading skeleton ───────────────────────────────────────────────── */
.btech-avatar--loading {
  background: var(--bg-subtler, #dbdde1);
}
.btech-avatar__skeleton {
  width: 100%;
  height: 100%;
  background: linear-gradient(90deg, transparent, rgba(255, 255, 255, 0.4), transparent);
  background-size: 200% 100%;
  animation: btech-avatar-shimmer 1.4s infinite;
}
@keyframes btech-avatar-shimmer {
  from { background-position: 200% 0; }
  to   { background-position: -200% 0; }
}

.btech-avatar__initials {
  display: inline-block;
  line-height: 1;
}

/* ── BTAvatarGroup — stacked horizontal layout w/ overflow counter ──── */
.btech-avatar-group {
  display: inline-flex;
  align-items: center;
  position: relative;
}

.btech-avatar-group__item,
.btech-avatar-group__overflow {
  flex-shrink: 0;
}

.btech-avatar-group__item + .btech-avatar-group__item,
.btech-avatar-group__item + .btech-avatar-group__overflow,
.btech-avatar-group__overflow {
  margin-left: -12px;
}
.btech-avatar-group--xs  .btech-avatar-group__item + .btech-avatar-group__item,
.btech-avatar-group--xs  .btech-avatar-group__item + .btech-avatar-group__overflow,
.btech-avatar-group--xs  .btech-avatar-group__overflow { margin-left: -8px; }

.btech-avatar-group--sm  .btech-avatar-group__item + .btech-avatar-group__item,
.btech-avatar-group--sm  .btech-avatar-group__item + .btech-avatar-group__overflow,
.btech-avatar-group--sm  .btech-avatar-group__overflow { margin-left: -10px; }

.btech-avatar-group--md  .btech-avatar-group__item + .btech-avatar-group__item,
.btech-avatar-group--md  .btech-avatar-group__item + .btech-avatar-group__overflow,
.btech-avatar-group--md  .btech-avatar-group__overflow { margin-left: -12px; }

.btech-avatar-group--lg  .btech-avatar-group__item + .btech-avatar-group__item,
.btech-avatar-group--lg  .btech-avatar-group__item + .btech-avatar-group__overflow,
.btech-avatar-group--lg  .btech-avatar-group__overflow { margin-left: -16px; }

.btech-avatar-group--xl  .btech-avatar-group__item + .btech-avatar-group__item,
.btech-avatar-group--xl  .btech-avatar-group__item + .btech-avatar-group__overflow,
.btech-avatar-group--xl  .btech-avatar-group__overflow { margin-left: -20px; }

.btech-avatar-group--2xl .btech-avatar-group__item + .btech-avatar-group__item,
.btech-avatar-group--2xl .btech-avatar-group__item + .btech-avatar-group__overflow,
.btech-avatar-group--2xl .btech-avatar-group__overflow { margin-left: -32px; }

.btech-avatar-group__overflow {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  background: var(--bg-subtler, #dbdde1);
  color: var(--text-secondary, #64748b);
  border-radius: var(--radius-rd, 9999px);
  font-family: 'Geist', system-ui, -apple-system, sans-serif;
  font-weight: 500;
  user-select: none;
}

.btech-avatar__count {
  display: inline-block;
  line-height: 1;
}

/**
 * BTAvatar v2 — circular badge with image, initials, empty, or error state.
 * Sliced from Figma `Avatar` (node 497:979). Mirrors @btech/ui-vue +
 * btech_ui (Flutter) one-to-one (same prop names, same variant
 * precedence, same render priority).
 *
 * ## Variant precedence (highest first):
 *   1. isLoading=true              → skeleton placeholder
 *   2. status='error' | imageError → hide_image icon on bg/subtler
 *   3. item == undefined           → person icon on bg/subtler (empty)
 *   4. item.imageUrl               → <img>; onError → error state
 *   5. (default)                   → initials on colored background
 *
 * ## Usage:
 * ```tsx
 * <BTAvatar item={{ name: 'Faisal Lestari' }} size="md" />
 * <BTAvatar item={{ name: 'JD', imageUrl: 'https://...' }} size="lg" />
 * <BTAvatar item={{ name: 'AB', color: 'purple' }} />
 * <BTAvatar item={{ name: '?' }} isLoading />
 * <BTAvatar status="error" />
 * <BTAvatar />
 * ```
 */
import * as React from 'react';
import type { BTAvatarProps } from './BTAvatar.types.js';
import { deriveInitials } from './BTAvatar.types.js';
import './BTAvatar.css';

// ── Icon SVGs (Material Design paths, inline — no external dep) ──────────────

/** Material `person` icon (filled 24x24) — empty state. */
const PersonIcon = () => (
  <svg viewBox="0 0 24 24" aria-hidden="true" fill="currentColor">
    <path d="M12 12c2.21 0 4-1.79 4-4s-1.79-4-4-4-4 1.79-4 4 1.79 4 4 4zm0 2c-2.67 0-8 1.34-8 4v2h16v-2c0-2.66-5.33-4-8-4z" />
  </svg>
);

/** Material `hide_image` icon (outlined 24x24) — error state. */
const HideImageIcon = () => (
  <svg viewBox="0 0 24 24" aria-hidden="true" fill="currentColor">
    <path d="M21 3H3c-1.1 0-2 .9-2 2v14c0 1.1.9 2 2 2h18c1.1 0 2-.9 2-2V5c0-1.1-.9-2-2-2zm0 16H3V5h18v14zM18.5 10l-5.33 6.5-3.67-4.34L6 17h12l-2.5-3.33z" />
    <path d="M4.34 2.93 2.93 4.34 19.07 20.48l1.41-1.41z" />
  </svg>
);

// ────────────────────────────────────────────────────────────────────────────

const cn = (...parts: Array<string | false | null | undefined>): string =>
  parts.filter(Boolean).join(' ');

export const BTAvatar: React.FC<BTAvatarProps> = ({
  item,
  size = 'md',
  isLoading = false,
  status,
  className,
}) => {
  const [imageErrored, setImageErrored] = React.useState(false);

  // Reset error state when imageUrl changes
  React.useEffect(() => {
    setImageErrored(false);
  }, [item?.imageUrl]);

  // Resolve variant — order MUST match Vue/Flutter precedence
  const variant: 'loading' | 'error' | 'empty' | 'image' | 'initials' =
    isLoading
      ? 'loading'
      : status === 'error' || imageErrored
        ? 'error'
        : item == null
          ? 'empty'
          : item.imageUrl && !imageErrored
            ? 'image'
            : 'initials';

  const colorClass =
    variant === 'initials' || variant === 'image'
      ? `btech-avatar--color-${item?.color ?? 'green'}`
      : null;

  const classes = cn(
    'btech-avatar',
    `btech-avatar--${size}`,
    `btech-avatar--${variant}`,
    colorClass,
    className,
  );

  return (
    <div
      data-slot="avatar"
      data-size={size}
      data-variant={variant}
      className={classes}
      role="img"
      aria-label={item?.name ?? (variant === 'error' ? 'Error' : 'Empty')}
    >
      {variant === 'loading' && <div className="btech-avatar__skeleton" />}

      {variant === 'error' && (
        <span className="btech-avatar__icon">
          <HideImageIcon />
        </span>
      )}

      {variant === 'empty' && (
        <span className="btech-avatar__icon">
          <PersonIcon />
        </span>
      )}

      {variant === 'image' && item?.imageUrl && (
        <img
          className="btech-avatar__img"
          src={item.imageUrl}
          alt={item.name}
          onError={() => setImageErrored(true)}
        />
      )}

      {variant === 'initials' && item && (
        <span className="btech-avatar__initials">{deriveInitials(item.name)}</span>
      )}
    </div>
  );
};

BTAvatar.displayName = 'BTAvatar';

/**
 * BTAvatar v2 — public API types.
 *
 * Sliced from Figma `Avatar` (node 497:979). Data-class API mirrors
 * @btech/ui-vue + btech_ui Flutter one-to-one. Cross-framework parity
 * is mandatory: prop names, variant precedence, and render priority
 * MUST match across all 3 frameworks.
 *
 * Variant precedence (highest first):
 *   1. isLoading=true              → skeleton placeholder
 *   2. status='error' | imageError → hide_image icon on bg/subtler
 *   3. item == null/undefined      → person icon on bg/subtler (empty)
 *   4. item.imageUrl               → <img>; onError → triggers error state
 *   5. (default)                   → initials on colored background
 */

export type BTAvatarSize = 'xs' | 'sm' | 'md' | 'lg' | 'xl' | '2xl';

/** Component-specific palette (hardcoded per Figma 497:979). NOT tokenized. */
export type BTAvatarColor =
  | 'green'
  | 'blue'
  | 'orange'
  | 'purple'
  | 'teal'
  | 'pink';

/**
 * Explicit override variants from Figma 497:979.
 * `'error'` renders a hide_image icon on bg/subtler background.
 *  Also triggered automatically when `item.imageUrl` fails to load.
 */
export type BTAvatarStatus = 'error';

/** Avatar payload. `name` is required and used to auto-derive initials. */
export interface BTAvatarItem {
  /** Used to derive initials. e.g. "Faisal Lestari" → "FL". */
  name: string;
  /** When provided, renders as <img>. Falls back to error icon on load failure. */
  imageUrl?: string;
  /** Background color for initials variant. Defaults to `green`. */
  color?: BTAvatarColor;
}

export interface BTAvatarProps {
  /**
   * The avatar payload. When `undefined`, renders the empty (person icon)
   * variant — Figma's explicit "no user" state.
   */
  item?: BTAvatarItem;
  /** Size of the avatar circle. Defaults to `md` (40px). */
  size?: BTAvatarSize;
  /** When `true`, renders a skeleton placeholder. */
  isLoading?: boolean;
  /**
   * Explicit override to the error variant (hide_image icon).
   * Useful when the caller already knows the asset is unavailable.
   */
  status?: BTAvatarStatus;
  /** Pass-through className for layout overrides. */
  className?: string;
}

/** Derive 1-2 character initials from a person's name. Mirrors Vue + Flutter. */
export function deriveInitials(name: string): string {
  const trimmed = (name ?? '').trim();
  if (!trimmed) return '?';
  const words = trimmed.split(/\s+/);
  if (words.length === 1) return words[0]!.charAt(0).toUpperCase();
  const first = words[0]!.charAt(0);
  const last = words[words.length - 1]!.charAt(0);
  return (first + last).toUpperCase();
}
